#include <algorithm>
#include <numeric>
#include <climits>

using namespace std;

struct DSU {
    vector<int> parent;
    DSU(int n) : parent(n) {
        iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }
    bool unite(int x, int y) {
        x = find(x);
        y = find(y);
        if (x == y) return false;
        parent[y] = x;
        return true;
    }
};

long long solve(long long n, std::vector<std::vector<long long>> edges, long long k) {
    vector<vector<long long>> must_edges;
    vector<vector<long long>> optional_edges;
    for (const auto& e : edges) {
        if (e[3] == 1) {
            must_edges.push_back(e);
        } else {
            optional_edges.push_back(e);
        }
    }

    DSU dsu(n);
    int components = n;
    for (const auto& e : must_edges) {
        if (dsu.unite(e[0], e[1])) {
            components--;
        }
    }

    if (components > 1) {
        return -1;
    }

    auto can_form_spanning_tree = [&](long long min_s) {
        DSU temp_dsu(n);
        int temp_components = n;
        int used_k = 0;

        for (const auto& e : must_edges) {
            if (e[2] < min_s) return false;
            if (temp_dsu.unite(e[0], e[1])) {
                temp_components--;
            }
        }

        vector<vector<long long>> candidates;
        for (const auto& e : optional_edges) {
            if (e[2] >= min_s) {
                candidates.push_back({e[2], e[0], e[1]});
            } else if (e[2] * 2 >= min_s) {
                candidates.push_back({e[2] * 2, e[0], e[1]});
            }
        }

        sort(candidates.begin(), candidates.end());
        for (const auto& e : candidates) {
            if (temp_dsu.unite(e[1], e[2])) {
                temp_components--;
                if (e[0] == e[2] * 2) {
                    used_k++;
                }
            }
            if (temp_components == 1) break;
        }

        return temp_components == 1 && used_k <= k;
    };

